SET SERVEROUTPUT ON;

-- =========================================================
-- LMS Oracle seed data
-- Safe reset order: child tables -> parent tables
-- Uses explicit IDs so MongoDB seed data can reference them reliably.
-- =========================================================

BEGIN EXECUTE IMMEDIATE 'DELETE FROM certifications'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DELETE FROM payments'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DELETE FROM enrollments'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DELETE FROM modules'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DELETE FROM courses'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DELETE FROM students'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DELETE FROM instructors'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
COMMIT;

-- Optional identity reset
BEGIN EXECUTE IMMEDIATE 'ALTER TABLE certifications MODIFY certificate_id GENERATED BY DEFAULT AS IDENTITY (START WITH 1)'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'ALTER TABLE payments MODIFY payment_id GENERATED BY DEFAULT AS IDENTITY (START WITH 1)'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'ALTER TABLE enrollments MODIFY enrollment_id GENERATED BY DEFAULT AS IDENTITY (START WITH 1)'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'ALTER TABLE modules MODIFY module_id GENERATED BY DEFAULT AS IDENTITY (START WITH 1)'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'ALTER TABLE courses MODIFY course_id GENERATED BY DEFAULT AS IDENTITY (START WITH 1)'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'ALTER TABLE students MODIFY student_id GENERATED BY DEFAULT AS IDENTITY (START WITH 1)'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'ALTER TABLE instructors MODIFY instructor_id GENERATED BY DEFAULT AS IDENTITY (START WITH 1)'; EXCEPTION WHEN OTHERS THEN NULL; END;
/

